import Nav from "@/components/Nav";
import HeroSection from "@/components/HeroSection";
import Footer from "@/components/Footer";
import FloatingAgent from "@/components/FloatingAgent";
import Link from "next/link";
import Image from "next/image";

export default function Home() {
  return (
    <>
      <Nav />
      <main>
        <HeroSection />

        {/* Hub Previews (Linear-style alternating) */}

        {/* Websites Preview */}
        <section className="px-6 py-32 border-t border-white/5 bg-[#050505]">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center gap-20">
            <div className="flex-1">
              <p className="section-label">Websites</p>
              <h2 className="text-5xl font-black text-white mb-6 uppercase tracking-tighter">Engineered to <span className="text-cyan-500">Convert</span></h2>
              <p className="text-xl text-zinc-400 mb-10 leading-relaxed">
                We build Next.js performance engines for elite brands. 10-day sprint from kickoff to live production.
              </p>
              <Link href="/websites" className="text-cyan-500 font-black uppercase tracking-widest text-xs hover:text-cyan-400 transition-colors">
                Explore the Portfolio →
              </Link>
            </div>
            <div className="flex-1 rounded-3xl overflow-hidden border border-white/10 shadow-2xl scale-105 md:scale-110">
              <Image src="/site-epicurean.png" alt="Website Preview" width={800} height={500} className="w-full h-auto grayscale opacity-50 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-500" />
            </div>
          </div>
        </section>

        {/* Dashboards Preview */}
        <section className="px-6 py-32 border-t border-white/5 bg-black">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row-reverse items-center gap-20">
            <div className="flex-1">
              <p className="section-label">Dashboards</p>
              <h2 className="text-5xl font-black text-white mb-6 uppercase tracking-tighter">Your Data, <span className="text-blue-500">Weaponized</span></h2>
              <p className="text-xl text-zinc-400 mb-10 leading-relaxed">
                Live revenue intelligence and lead tracking. Stop guessing and start scaling with neural-grid analytics.
              </p>
              <Link href="/dashboards" className="text-blue-500 font-black uppercase tracking-widest text-xs hover:text-blue-400 transition-colors">
                See the Lab →
              </Link>
            </div>
            <div className="flex-1 rounded-3xl overflow-hidden border border-white/10 shadow-2xl">
              <Image src="/dashboard-preview.png" alt="Dashboard Preview" width={800} height={500} className="w-full h-auto opacity-60" />
            </div>
          </div>
        </section>

        {/* Ads Preview */}
        <section className="px-6 py-32 border-t border-white/5 bg-[#050505]">
          <div className="max-w-7xl mx-auto text-center max-w-4xl">
            <p className="section-label justify-center">Creative</p>
            <h2 className="text-5xl font-black text-white mb-6 uppercase tracking-tighter">Hyper-Realistic <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-indigo-600">Ad Lab</span></h2>
            <p className="text-xl text-zinc-400 mb-12">
              From studio shots to Time Square billboards in 24 hours. Cinematic AI creative at fractional costs.
            </p>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-16">
              <div className="aspect-square bg-zinc-900 rounded-2xl border border-white/5 overflow-hidden">
                <Image src="/ad-porsche.png" alt="Ad 1" width={300} height={300} className="object-cover w-full h-full opacity-40 hover:opacity-100 transition-opacity" />
              </div>
              <div className="aspect-square bg-zinc-900 rounded-2xl border border-white/5 overflow-hidden">
                <Image src="/ad-watch.png" alt="Ad 2" width={300} height={300} className="object-cover w-full h-full opacity-40 hover:opacity-100 transition-opacity" />
              </div>
              <div className="aspect-square bg-zinc-900 rounded-2xl border border-white/5 overflow-hidden">
                <Image src="/ad-food.png" alt="Ad 3" width={300} height={300} className="object-cover w-full h-full opacity-40 hover:opacity-100 transition-opacity" />
              </div>
              <div className="aspect-square bg-zinc-900 rounded-2xl border border-white/5 overflow-hidden">
                <Image src="/ad-porsche-context.png" alt="Ad 4" width={300} height={300} className="object-cover w-full h-full opacity-40 hover:opacity-100 transition-opacity" />
              </div>
            </div>
            <Link href="/ads" className="px-10 py-5 rounded-2xl bg-white text-black font-black uppercase tracking-widest text-xs hover:bg-zinc-200 transition-all">
              Enter the Creative Lab
            </Link>
          </div>
        </section>

      </main>
      <Footer />
      <FloatingAgent />
    </>
  );
}
